using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    // Default type-info resolver so common types are known
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// ── 1. Strongly-typed retrieval ──────────────────────────────────
// GetTypeInfo<T>() returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Type  : {personInfo.Type.Name}");
Console.WriteLine($"Kind  : {personInfo.Kind}");
Console.WriteLine($"Props : {string.Join(", ", personInfo.Properties.Select(p => p.Name))}");

// Quick round-trip to prove the metadata works
var json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
var back = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"RT    : {back}");
Console.WriteLine();

// ── 2. Probe without throwing ────────────────────────────────────
// TryGetTypeInfo returns false instead of throwing when metadata
// isn't available for the requested type.
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"Person metadata found  – type: {found!.Type.Name}");
else
    Console.WriteLine("Person metadata NOT found");

// Stream is unlikely to have metadata with the default resolver config
// used here, but even "normal" types just return true/false — no exception.
if (options.TryGetTypeInfo(typeof(Stream), out _))
    Console.WriteLine("Stream metadata found");
else
    Console.WriteLine("Stream metadata NOT found (expected)");

// ── helper record ────────────────────────────────────────────────
public record Person(string Name, int Age);

